module packet_filter (  
    input [4:0] deny_packet,  
    input [4:0] rule0,  
    input [4:0] rule1,  
    input [4:0] rule2,  
    input [4:0] rule3,  
    input [4:0] rule4,  
    output reg allow  
);  
    always @(*) begin  
        if (deny_packet == rule0 || deny_packet == rule1 || deny_packet == rule2 || deny_packet == rule3 || deny_packet == rule4)  
            allow = 1;  
        else  
            allow = 0;  
    end  
endmodule
